import base64, hashlib, sys

# นี่คือส่วนของโค้ดวิเคราะห์หุ้นที่ถูกเข้ารหัสไว้ (อ่านไม่ออก)
_0x4f2a = ""

def _run_app():
    print("="*40)
    print(" 🔒 SYSTEM PROTECTED | กรุณาใส่รหัสผ่าน")
    print("="*40)
    p = input("Password: ")
    
    # ถอดรหัสลับในหน่วยความจำ (RAM)
    k = hashlib.sha256(p.encode()).digest()
    try:
        d = base64.b64decode(_0x4f2a)
        res = bytearray()
        for i, b in enumerate(d):
            res.append(b ^ k[i % len(k)])
        
        # สั่งรันโค้ดที่ถอดรหัสแล้วทันที (ไม่สร้างไฟล์ใหม่)
        exec(res.decode('utf-8'), globals())
    except Exception:
        print("\n❌ Access Denied: รหัสผ่านไม่ถูกต้อง")
        input("กด Enter เพื่อออก...")
        sys.exit()

if __name__ == "__main__":
    _run_app()
